  2	
  3	import (
  4		"errors"
  5		"fmt"
  6		"image/png"
  7		"os"
  8		"path/filepath"
  9	)
 10	
 11	type renderProgress struct {
 12		CurrentFrame int
 13		TotalFrames  int
 14		Filename     string
 15	}
 16	
 17	var errRenderCancelled = errors.New("render cancelled")
 18	
 19	type overwriteConflictError struct {
 20		Path string
 21	}
 22	
 23	func (e overwriteConflictError) Error() string {
 24		return "render output already exists: " + e.Path
 25	}
 26	
 27	func prepareRenderProject(project Project, allowOverwrite bool) (Project, error) {
 28		project = normalizeProject(project)
 29		outputFolder := project.Export.OutputFolder
 30		if outputFolder == "" {
 31			outputFolder = "."
 32		}
 33		prefix := project.Export.FilePrefix
 34		if prefix == "" {
 35			prefix = "frame"
 36		}
 37	
 38		switch project.Export.OverwritePolicy {
 39		case "Create new suffix":
 40			project.Export.FilePrefix = nextAvailablePrefix(outputFolder, prefix, project)
 41			return project, nil
 42		case "Overwrite":
 43			return project, nil
 44		default:
 45			if conflict := firstExistingFrame(outputFolder, prefix, project); conflict != "" && !allowOverwrite {
 46				return project, overwriteConflictError{Path: conflict}
 47			}
 48			return project, nil
 49		}
 50	}
 51	
 52	func renderPNGSequence(project Project, cancel <-chan struct{}, progress func(renderProgress)) (string, int, error) {
 53		stats := analyzeText(project.Text.Content, project.Charset.Languages, project.Text.UppercaseOnly, project.Text.AutoReplaceUnsupported)
 54		outputFolder := project.Export.OutputFolder
 55		if outputFolder == "" {
 56			outputFolder = "."
 57		}
 58		if err := os.MkdirAll(outputFolder, 0o755); err != nil {
 59			return "", 0, err
 60		}
 61	
 62		prefix := project.Export.FilePrefix
 63		if prefix == "" {
 64			prefix = "frame"
 65		}
 66	
 67		totalFrames := maxInt(project.Export.EndFrame-project.Export.StartFrame+1, 1)
 68		count := 0
 69		for frame := project.Export.StartFrame; frame <= project.Export.EndFrame; frame++ {
 70			select {
 71			case <-cancel:
 72				return outputFolder, count, errRenderCancelled
 73			default:
 74			}
 75	
 76			img, err := renderImage(project, stats, frame, project.Export.Width, project.Export.Height)
 77			if err != nil {
 78				return "", count, err
 79			}
 80	
 81			filename := filepath.Join(outputFolder, fmt.Sprintf("%s_%05d.png", prefix, frame))
 82			file, err := os.Create(filename)
 83			if err != nil {
 84				return "", count, err
 85			}
 86	
 87			if err := png.Encode(file, img); err != nil {
 88				_ = file.Close()
 89				return "", count, err
 90			}
 91			if err := file.Close(); err != nil {
 92				return "", count, err
 93			}
 94	
 95			count++
 96			if progress != nil {
 97				progress(renderProgress{
 98					CurrentFrame: count,
 99					TotalFrames:  totalFrames,
100					Filename:     filename,
101				})
102			}
103		}
104	
105		return outputFolder, count, nil
106	}
107	
108	func nextAvailablePrefix(outputFolder, prefix string, project Project) string {
109		if firstExistingFrame(outputFolder, prefix, project) == "" {
110			return prefix
111		}
112		for suffix := 1; suffix < 1000; suffix++ {
113			candidate := fmt.Sprintf("%s_%02d", prefix, suffix)
114			if firstExistingFrame(outputFolder, candidate, project) == "" {
115				return candidate
116			}
117		}
118		return prefix + "_new"
119	}
120	
121	func firstExistingFrame(outputFolder, prefix string, project Project) string {
122		for frame := project.Export.StartFrame; frame <= project.Export.EndFrame; frame++ {
123			filename := filepath.Join(outputFolder, fmt.Sprintf("%s_%05d.png", prefix, frame))
124			if _, err := os.Stat(filename); err == nil {
125				return filename
126			}
127		}
128		return ""
129	}

