		drawPlaceholderBands(img, color.NRGBA{R: 83, G: 52, B: 89, A: 255}, color.NRGBA{R: 28, G: 20, B: 32, A: 255})
	default:
		draw.Draw(img, bounds, image.NewUniform(color.NRGBA{R: 5, G: 6, B: 8, A: 255}), image.Point{}, draw.Src)
