package main

import (
	"hash/fnv"
	"math"
	"math/rand"
	"sort"
	"strconv"
	"strings"
)

type animatedFrame struct {
	Text  string
	Frame int
	Time  float64
}

func buildAnimatedFrame(project Project, stats textStats, frame int) animatedFrame {
	fps := maxInt(project.Export.FPS, 1)
	normalizedFrame := maxInt(frame-project.Export.StartFrame, 0)
	return animatedFrame{
		Text:  animateText(project, stats.DisplayText, normalizedFrame, fps),
		Frame: frame,
		Time:  float64(normalizedFrame) / float64(fps),
	}
}

func animateText(project Project, finalText string, frame, fps int) string {
	runes := []rune(finalText)
	animatable := animatablePositions(runes)
	if len(animatable) == 0 {
		return finalText
	}

	introFrames := int(project.Animation.IntroDelay * float64(fps))
	outroFrames := int(project.Animation.OutroHold * float64(fps))
	totalFrames := maxInt(int(project.Animation.TotalDuration*float64(fps)), introFrames+outroFrames+1)
	finalLockFrame := maxInt(totalFrames-outroFrames, 1)

	if frame >= finalLockFrame {
		return finalText
	}

	perCharFrames := maxInt(int(project.Animation.PerCharacterDelay*float64(fps)), 1)
	scrambleWindow := maxInt(finalLockFrame/maxInt(len(animatable), 1), 3)
	scrambleWindow = maxInt(scrambleWindow, perCharFrames*2)
	order := orderIndices(animatable, runes, project.Animation.LockOrder, project.Animation.Seed)
	pool := buildRandomPool(project)
	seedBase := hashSeed(project.Animation.Seed)
	switchFrame := scrambleSwitchFrame(frame, project.Animation.RandomSwitchRate, fps)

	out := make([]rune, len(runes))
	copy(out, runes)

	for rank, idx := range order {
		r := runes[idx]
		if r == '\n' || r == ' ' || r == '\t' {
			continue
		}

		start := introFrames + rank*perCharFrames
		lockAt := minInt(start+scrambleWindow, finalLockFrame)
		if frame >= lockAt {
			continue
		}

		out[idx] = animateRuneForMode(project, pool, seedBase, frame, switchFrame, idx, r, start, lockAt, perCharFrames)
	}

	return string(out)
}

func animateRuneForMode(project Project, pool []rune, seedBase uint64, frame, switchFrame, index int, target rune, start, lockAt, perCharFrames int) rune {
	switch project.Animation.Type {
	case "Scramble basic":
		return scrambleRune(pool, seedBase, switchFrame, index, target, project.Animation.AllowEmptyCell)
	case "Reveal then scramble then lock":
		revealUntil := minInt(start+perCharFrames, lockAt)
		if frame < start {
			return ' '
		}
		if frame < revealUntil {
			return target
		}
		return lockOrScrambleRune(project, pool, seedBase, frame, switchFrame, index, target, revealUntil, lockAt)
	default:
		if frame < start {
			return scrambleRune(pool, seedBase, switchFrame, index, target, project.Animation.AllowEmptyCell)
		}
		return lockOrScrambleRune(project, pool, seedBase, frame, switchFrame, index, target, start, lockAt)
	}
}

func lockOrScrambleRune(project Project, pool []rune, seedBase uint64, frame, switchFrame, index int, target rune, start, lockAt int) rune {
	progress := float64(frame-start) / float64(maxInt(lockAt-start, 1))
	switch project.Animation.LockMode {
	case "Hard lock":
		return scrambleRune(pool, seedBase, switchFrame, index, target, project.Animation.AllowEmptyCell)
	default:
		if deterministicChance(seedBase, frame, index) < progress {
			return target
		}
		return scrambleRune(pool, seedBase, switchFrame, index, target, project.Animation.AllowEmptyCell)
	}
}

func buildRandomPool(project Project) []rune {
	switch project.Animation.RandomSource {
	case "Digits only":
		return []rune("0123456789")
	case "Letters only":
		return []rune("REDACTED")
	case "Alphanumeric":
		return []rune("REDACTED")
	default:
		pool := make([]rune, 0, 128)
		for r := range supportedRunes(project.Charset.Languages) {
			if r == '\n' || r == ' ' || r == '\t' {
				continue
			}
			if !project.Animation.AllowInvalidRandomChars && !isLetterOrDigit(r) {
				continue
			}
			pool = append(pool, r)
		}
		sort.Slice(pool, func(i, j int) bool { return pool[i] < pool[j] })
		if len(pool) == 0 {
			return []rune("REDACTED")
		}
		return pool
	}
}

func scrambleRune(pool []rune, seedBase uint64, switchFrame, index int, fallback rune, allowEmpty bool) rune {
	if allowEmpty && deterministicChance(seedBase, switchFrame, index+991) < 0.08 {
		return ' '
	}
	if len(pool) == 0 {
		return fallback
	}
	rng := rand.New(rand.NewSource(int64(seedBase) + int64(switchFrame*131) + int64(index*17)))
	return pool[rng.Intn(len(pool))]
}

func scrambleSwitchFrame(frame int, switchRate float64, fps int) int {
	if frame <= 0 || fps <= 0 {
		return 0
	}
	if switchRate <= 0 {
		return frame
	}
	return int(math.Floor(float64(frame) * switchRate / float64(fps)))
}

func deterministicChance(seedBase uint64, frame, index int) float64 {
	value := hashSeed(strconv.FormatUint(seedBase, 10) + ":" + strconv.Itoa(frame) + ":" + strconv.Itoa(index))
	return float64(value%1000) / 1000.0
}

func hashSeed(seed string) uint64 {
	h := fnv.New64a()
	if strings.TrimSpace(seed) == "" {
		seed = "default-seed"
	}
	_, _ = h.Write([]byte(seed))
	return h.Sum64()
}

func animatablePositions(runes []rune) []int {
	positions := make([]int, 0, len(runes))
	for i, r := range runes {
		if r == '\n' {
			continue
		}
		positions = append(positions, i)
	}
	return positions
}

