func alphaBounds(img *image.Alpha) (image.Rectangle, bool) {
	minX := img.Bounds().Max.X
	minY := img.Bounds().Max.Y
	maxX := img.Bounds().Min.X
	maxY := img.Bounds().Min.Y
	found := false

	for y := img.Bounds().Min.Y; y < img.Bounds().Max.Y; y++ {
